from anthropic import Anthropic

client = Anthropic()
batsman_profile = "Virat Kohli vs pace bowling: aggressive drives, weak against yorkers, career avg 59.18"

response = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1024,
    system=[
        {
            "type": "text",
            "text": "You are a cricket strategy analyst. Provide tactical recommendations."
        },
        {
            "type": "text",
            "text": f"Player Context: {batsman_profile}",
            "cache_control": {"type": "ephemeral"}
        }
    ],
    messages=[
        {"role": "user", "content": "What's the optimal bowling plan for this batsman?"}
    ]
)
# Context cached on first call, reused on subsequent messages
print(f"Cache creation tokens: {response.usage.cache_creation_input_tokens}")
print(f"Cache read tokens: {response.usage.cache_read_input_tokens}")
